create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, email text unique not null, role text not null default 'USER', created_at timestamptz default now());
create table if not exists public.products (id bigserial primary key, name text not null, description text, price integer not null, old_price integer, category text, image_url text, stock integer default 0, rating numeric default 5, created_at timestamptz default now());
create table if not exists public.orders (id bigserial primary key, user_id uuid references auth.users(id), customer_name text, phone text, email text, address text, status text default 'new', total integer default 0, created_at timestamptz default now());
